before_code:
module decoder_priority(
  input [7:0] request_bits, priority_mask,
  output reg [7:0] grant
);

  always @(request_bits) begin
    grant = 8'b0;
    for (int i = 0; i < 8; i++) begin
      if (request_bits[i] && priority_mask[i])
        grant[i] = 1'b1;
    end
  end

endmodule

after_code:
module decoder_priority(
  input [7:0] request_bits, priority_mask,
  output reg [7:0] grant
);

  always @(*) begin
    grant = 8'b0;
    for (int i = 0; i < 8; i++) begin
      if (request_bits[i] && priority_mask[i])
        grant[i] = 1'b1;
    end
  end

endmodule
